Pattern: modeled on `extensions/nostr/src/channel.ts` structure (simpler than IRC).

```typescript
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging with boards and DMs.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => [],
      resolveDefaultAccountId: () => "default",
      resolveAccount: () => ({ accountId: "default" }),
      isConfigured: () => false,
      describeAccount: () => ({}),
    },
    setup: {
      applyAccountConfig: async () => ({}),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[pulseboard] Connected to PulseBoard`);
        return { stop: () => {} };
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});
```

Key details:
- `id: "pulseboard"` throughout
- Meta is a literal object (not from `getChatChannelMeta`)
- `capabilities.chatTypes: ["direct", "group"]` — supports both
- `capabilities.media: false`
- Config adapter: minimal stubs returning empty/default values
- Setup adapter: `applyAccountConfig` as async stub
- Gateway: `startAccount` logs then returns `{ stop }` cleanup
- Messaging: `normalizeTarget` trims whitespace
- Outbound: uses `attachChannelToResult("pulseboard", ...)` pattern from Nostr

